{
  "name": "Weibo Chat Archiver",
  "description": "A powerful utility to back up, parse, and analyze Weibo chat histories. Use Gemini to intelligently clean raw network data into structured archives.",
  "requestFramePermissions": []
}

export interface WeiboMessage {
  id: string;
  senderName: string;
  senderId: string;
  content: string;
  timestamp: string; // ISO format
  avatar?: string;
}

export interface ChatArchive {
  id: string;
  groupName: string;
  groupUid: string;
  createdAt: string;
  messages: WeiboMessage[];
}

export enum ViewState {
  DASHBOARD = 'DASHBOARD',
  IMPORT = 'IMPORT',
  HISTORY = 'HISTORY',
  ANALYTICS = 'ANALYTICS'
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { GoogleGenAI, Type } from "@google/genai";
import { WeiboMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const parseRawChatData = async (rawText: string): Promise<WeiboMessage[]> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Parse the following raw text or JSON snippet from a Weibo chat interface/network log into a clean array of message objects. 
    Handle various formats including messy copy-pastes or raw API JSON. 
    Normalize timestamps to ISO 8601 strings. If sender names are missing, use "User_[ID]".

    Data:
    ${rawText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            senderName: { type: Type.STRING },
            senderId: { type: Type.STRING },
            content: { type: Type.STRING },
            timestamp: { type: Type.STRING },
            avatar: { type: Type.STRING }
          },
          required: ["id", "senderName", "content", "timestamp"]
        }
      }
    }
  });

  try {
    const text = response.text.trim();
    return JSON.parse(text);
  } catch (error) {
    console.error("Failed to parse Gemini response:", error);
    return [];
  }
};

