export default ChatHistory;

import React, { useState } from 'react';
import { parseRawChatData } from '../services/gemini';
import { WeiboMessage, ChatArchive } from '../types';
import { Loader2, ClipboardCheck, Info, Terminal } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

interface DataImporterProps {
  onImport: (archive: ChatArchive) => void;
}

const DataImporter: React.FC<DataImporterProps> = ({ onImport }) => {
  const [rawText, setRawText] = useState('');
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState(1);

  const handleProcess = async () => {
    if (!rawText.trim()) return;
    setLoading(true);
    try {
      const messages = await parseRawChatData(rawText);
      if (messages.length > 0) {
        const newArchive: ChatArchive = {
          id: uuidv4(),
          groupName: "Weibo Chat Group", // Gemini can extract this if present
          groupUid: "-101",
          createdAt: new Date().toISOString(),
          messages: messages
        };
        onImport(newArchive);
        setRawText('');
        alert(`成功导入 ${messages.length} 条消息！`);
      } else {
        alert("未能从文本中提取出有效聊天记录。");
      }
    } catch (err) {
      console.error(err);
      alert("解析失败，请检查数据格式。");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="bg-white rounded-3xl shadow-xl overflow-hidden">
        <div className="p-8 border-b border-gray-100 bg-gradient-to-r from-indigo-500 to-purple-600 text-white">
          <h2 className="text-2xl font-bold mb-2">备份新聊天记录</h2>
          <p className="opacity-80">将微博网页版的原始数据转换为永久的结构化备份。</p>
        </div>

        <div className="p-8">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-8">
            <div className={`p-4 rounded-2xl border-2 transition-all ${step === 1 ? 'border-indigo-500 bg-indigo-50' : 'border-gray-100'}`}>
              <div className="w-8 h-8 rounded-full bg-indigo-600 text-white flex items-center justify-center font-bold mb-3">1</div>
              <h4 className="font-bold text-gray-900 mb-1">获取数据</h4>
              <p className="text-sm text-gray-500">打开微博网页版聊天，按 F12 进入控制台，在 Network 选项卡找到相关的 API 请求并复制响应内容。</p>
            </div>
            <div className={`p-4 rounded-2xl border-2 transition-all ${step === 2 ? 'border-indigo-500 bg-indigo-50' : 'border-gray-100'}`}>
              <div className="w-8 h-8 rounded-full bg-indigo-600 text-white flex items-center justify-center font-bold mb-3">2</div>
              <h4 className="font-bold text-gray-900 mb-1">粘贴内容</h4>
              <p className="text-sm text-gray-500">将原始 JSON 或可见的文本聊天记录粘贴到下方的输入框中。</p>
            </div>
            <div className={`p-4 rounded-2xl border-2 transition-all ${step === 3 ? 'border-indigo-500 bg-indigo-50' : 'border-gray-100'}`}>
              <div className="w-8 h-8 rounded-full bg-indigo-600 text-white flex items-center justify-center font-bold mb-3">3</div>
              <h4 className="font-bold text-gray-900 mb-1">AI 解析</h4>
              <p className="text-sm text-gray-500">点击解析按钮，Gemini 将自动整理数据并保存到本地存档。</p>
            </div>
          </div>

          <div className="relative">
            <textarea
              value={rawText}
              onChange={(e) => setRawText(e.target.value)}
              placeholder="在此粘贴原始聊天记录、JSON 响应或控制台日志..."
              className="w-full h-80 p-6 bg-gray-50 border border-gray-200 rounded-2xl focus:ring-4 focus:ring-indigo-100 focus:border-indigo-400 transition-all font-mono text-sm resize-none"
              onFocus={() => setStep(2)}
            />
            {rawText.length > 0 && !loading && (
              <button 
                onClick={() => setRawText('')}
                className="absolute top-4 right-4 p-2 text-gray-400 hover:text-rose-500 bg-white shadow-sm rounded-lg"
              >
                清空
              </button>
            )}
          </div>

          <div className="mt-8 flex items-center justify-between">
            <div className="flex items-center gap-2 text-sm text-indigo-600 font-medium">
              <Info className="w-4 h-4" />
              <span>数据仅保存在您的浏览器本地，不会上传至任何服务器。</span>
            </div>

            <button
              onClick={handleProcess}
              disabled={loading || !rawText.trim()}
              className={`flex items-center gap-2 px-8 py-4 rounded-2xl font-bold text-lg shadow-lg transition-all ${
                loading || !rawText.trim()
                  ? 'bg-gray-200 text-gray-400 cursor-not-allowed shadow-none'
                  : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-indigo-200'
              }`}
            >
              {loading ? (
                <>
                  <Loader2 className="w-5 h-5 animate-spin" />
                  解析中...
                </>
              ) : (
                <>
                  <ClipboardCheck className="w-5 h-5" />
                  开始解析 & 备份
                </>
              )}
            </button>
          </div>
        </div>
      </div>

      <div className="mt-8 p-6 bg-amber-50 rounded-2xl border border-amber-100 flex gap-4">
        <Terminal className="w-6 h-6 text-amber-600 flex-shrink-0" />
        <div>
          <h4 className="font-bold text-amber-900 text-sm">如何获取原始 JSON 数据？</h4>
          <p className="text-sm text-amber-800 mt-1">
            1. 访问 <code>api.weibo.com/chat</code> 并登录。<br/>
            2. 按 F12 打开开发者工具，切换到 <b>Network</b> 面板。<br/>
            3. 点击 <b>Fetch/XHR</b> 过滤请求。<br/>
            4. 寻找名称包含 <code>msgs</code> 或 <code>history</code> 的请求。<br/>
            5. 右键该请求选择 <b>Copy → Copy Response</b>，然后粘贴到上方。
          </p>
        </div>
      </div>
    </div>
  );
};

export default DataImporter;

import React, { useMemo } from 'react';
import { ChatArchive } from '../types';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  PieChart,
  Pie,
  Cell
} from 'recharts';

interface AnalyticsProps {
  archives: ChatArchive[];
}

const COLORS = ['#6366f1', '#a855f7', '#ec4899', '#f97316', '#10b981', '#3b82f6'];

const Analytics: React.FC<AnalyticsProps> = ({ archives }) => {
  const stats = useMemo(() => {
    const allMessages = archives.flatMap(a => a.messages);

    // Message count by user
    const userStatsMap: Record<string, number> = {};
    allMessages.forEach(m => {
      userStatsMap[m.senderName] = (userStatsMap[m.senderName] || 0) + 1;
    });

    const userStats = Object.entries(userStatsMap)
      .map(([name, count]) => ({ name, count }))
      .sort((a, b) => b.count - a.count)
      .slice(0, 10);

    // Activity by hour
    const hourStatsMap: Record<string, number> = {};
    allMessages.forEach(m => {
      const hour = new Date(m.timestamp).getHours();
      const label = `${hour}:00`;
      hourStatsMap[label] = (hourStatsMap[label] || 0) + 1;
    });

    const hourStats = Array.from({ length: 24 }).map((_, i) => ({
      hour: `${i}:00`,
      count: hourStatsMap[`${i}:00`] || 0
    }));

    return { userStats, hourStats, totalMessages: allMessages.length };
  }, [archives]);

  if (archives.length === 0) {
    return <div className="text-center py-20 text-gray-500">导入数据后即可查看分析图表</div>;
  }

  return (
    <div className="space-y-8">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
          <p className="text-sm font-medium text-gray-400 uppercase tracking-widest mb-1">总消息量</p>
          <h3 className="text-4xl font-black text-indigo-600">{stats.totalMessages}</h3>
        </div>
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
          <p className="text-sm font-medium text-gray-400 uppercase tracking-widest mb-1">总备份次数</p>
          <h3 className="text-4xl font-black text-purple-600">{archives.length}</h3>
        </div>
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
          <p className="text-sm font-medium text-gray-400 uppercase tracking-widest mb-1">活跃参与者</p>
          <h3 className="text-4xl font-black text-emerald-600">{stats.userStats.length}</h3>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
          <h4 className="text-lg font-bold text-gray-900 mb-6">活跃用户排行 (TOP 10)</h4>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.userStats} layout="vertical">
                <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f3f4f6" />
                <XAxis type="number" hide />
                <YAxis dataKey="name" type="category" width={80} axisLine={false} tickLine={false} style={{ fontSize: '12px' }} />
                <Tooltip 
                  cursor={{ fill: '#f9fafb' }}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="count" fill="#6366f1" radius={[0, 4, 4, 0]} barSize={20} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
          <h4 className="text-lg font-bold text-gray-900 mb-6">全天活跃时段分布</h4>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.hourStats}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f3f4f6" />
                <XAxis dataKey="hour" axisLine={false} tickLine={false} style={{ fontSize: '10px' }} />
                <YAxis axisLine={false} tickLine={false} style={{ fontSize: '10px' }} />
                <Tooltip 
                  cursor={{ fill: '#f9fafb' }}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="count" fill="#a855f7" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Analytics;

import React, { useState } from 'react';
import { ChatArchive } from '../types';
import { ArrowLeft, Search, Calendar, User } from 'lucide-react';
import { format } from 'date-fns';

interface ChatViewerProps {
  archive: ChatArchive;
  onBack: () => void;
}

const ChatViewer: React.FC<ChatViewerProps> = ({ archive, onBack }) => {
  const [search, setSearch] = useState('');

  const filteredMessages = archive.messages.filter(m => 
    m.content.toLowerCase().includes(search.toLowerCase()) ||
    m.senderName.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="h-full flex flex-col bg-gray-50 rounded-3xl overflow-hidden shadow-2xl border border-gray-200">
      <div className="bg-white p-6 border-b border-gray-100 flex items-center justify-between sticky top-0 z-10">
        <div className="flex items-center gap-4">
          <button 
            onClick={onBack}
            className="p-2 hover:bg-gray-100 rounded-full transition-colors"
          >
            <ArrowLeft className="w-5 h-5 text-gray-600" />
          </button>
          <div>
            <h3 className="font-bold text-lg text-gray-900 leading-none mb-1">{archive.groupName}</h3>
            <p className="text-xs text-gray-400">备份于 {format(new Date(archive.createdAt), 'yyyy/MM/dd HH:mm')}</p>
          </div>
        </div>

        <div className="relative w-72">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <input 
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="搜索消息内容或发送者..."
            className="w-full pl-10 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-100 focus:border-indigo-400 transition-all text-sm"
          />
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        {filteredMessages.map((msg, idx) => {
          const isFirstInSequence = idx === 0 || archive.messages[idx - 1].senderId !== msg.senderId;

          return (
            <div key={msg.id} className={`flex gap-3 ${msg.senderId === 'my_id' ? 'flex-row-reverse' : ''}`}>
              <div className={`w-10 h-10 rounded-2xl bg-indigo-100 flex items-center justify-center flex-shrink-0 ${!isFirstInSequence ? 'opacity-0' : ''}`}>
                {msg.avatar ? (
                  <img src={msg.avatar} alt={msg.senderName} className="w-full h-full rounded-2xl object-cover" />
                ) : (
                  <User className="w-5 h-5 text-indigo-400" />
                )}
              </div>
              <div className={`max-w-[70%] ${msg.senderId === 'my_id' ? 'items-end' : 'items-start'} flex flex-col`}>
                {isFirstInSequence && (
                  <div className="flex items-center gap-2 mb-1 px-1">
                    <span className="text-xs font-bold text-gray-700">{msg.senderName}</span>
                    <span className="text-[10px] text-gray-400">{format(new Date(msg.timestamp), 'HH:mm')}</span>
                  </div>
                )}
                <div className={`px-4 py-3 rounded-2xl text-sm leading-relaxed shadow-sm ${
                  msg.senderId === 'my_id' 
                    ? 'bg-indigo-600 text-white rounded-tr-none' 
                    : 'bg-white text-gray-800 border border-gray-100 rounded-tl-none'
                }`}>
                  {msg.content}
                </div>
              </div>
            </div>
          );
        })}
        {filteredMessages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-gray-400 py-20">
            <Search className="w-12 h-12 mb-4 opacity-20" />
            <p>没有找到匹配的消息</p>
          </div>
        )}
      </div>

      <div className="bg-white p-4 border-t border-gray-100 text-center text-[10px] text-gray-400 flex justify-center gap-4">
        <span className="flex items-center gap-1"><Calendar className="w-3 h-3" /> 数据归档 ID: {archive.id}</span>
        <span className="flex items-center gap-1"><User className="w-3 h-3" /> 原始 UID: {archive.groupUid}</span>
      </div>
    </div>
  );
};

export default ChatViewer;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import DataImporter from './components/DataImporter';
import ChatHistory from './components/ChatHistory';
import Analytics from './components/Analytics';
import ChatViewer from './components/ChatViewer';
import { ViewState, ChatArchive } from './types';
import { 
