import { WeiboMessage } from "../types";

/**
 * 本地解析逻辑：针对标准的微博 query_messages.json 格式进行快速提取
 * 这保证了隐私和处理速度
 */
const parseLocally = (rawText: string): WeiboMessage[] | null => {
  try {
    const data = JSON.parse(rawText);
    const messages = Array.isArray(data) ? data : (data.messages || []);

    if (messages.length > 0 && messages[0].mid) {
      return messages.map((msg: any) => ({
        id: msg.mid || msg.idstr || Math.random().toString(36).substr(2, 9),
        senderName: msg.user?.screen_name || '未知用户',
        senderId: msg.user?.idstr || 'unknown',
        content: msg.text || msg.content || '',
        timestamp: msg.created_at ? new Date(msg.created_at).toISOString() : new Date().toISOString(),
        avatar: msg.user?.profile_image_url || ''
      }));
    }
  } catch (e) {
    return null;
  }
  return null;
};

export const parseRawChatData = async (rawText: string): Promise<{ messages: WeiboMessage[], method: 'local' | 'ai' }> => {
  // 1. 尝试本地极速解析
  const localResult = parseLocally(rawText);
  if (localResult && localResult.length > 0) {
    console.log("检测到标准格式，已执行本地加密解析。");
    return { messages: localResult, method: 'local' };
  }

  // 2. 如果本地解析失败（非标准JSON或乱码），启用 Gemini 智能解析
  console.log("非标准格式，启动 Gemini 智能解析引擎...");
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `你是一个专业的微博数据解析专家。请将以下混杂的文本或损坏的 JSON 数据重组成结构化的聊天记录。

    必须输出严格的 JSON 数组，字段包含：id, senderName, senderId, content, timestamp (ISO格式), avatar。
    数据内容：
    ${rawText.substring(0, 15000)}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            senderName: { type: Type.STRING },
            senderId: { type: Type.STRING },
            content: { type: Type.STRING },
            timestamp: { type: Type.STRING },
            avatar: { type: Type.STRING }
          },
          required: ["id", "senderName", "content", "timestamp"]
        }
      }
    }
  });

  try {
    const text = response.text;
    if (!text) return { messages: [], method: 'ai' };
    return { messages: JSON.parse(text.trim()), method: 'ai' };
  } catch (error) {
    console.error("AI 解析失败:", error);
    return { messages: [], method: 'ai' };
  }
};

