/**
 * 微博数据本地解析器
 * 专门针对用户提供的原始 JSON 格式进行提取
 */
export const parseRawChatData = (rawText: string): { messages: WeiboMessage[] } => {
  try {
    const data = JSON.parse(rawText);
    const rawMessages = Array.isArray(data) ? data : (data.messages || []);

    const parsedMessages: WeiboMessage[] = rawMessages.map((msg: any) => {
      // 兼容多版本字段名
      const user = msg.from_user || msg.user || {};
      const timestamp = msg.time 
        ? new Date(msg.time * 1000).toISOString() // 处理 Unix 秒级时间戳
        : (msg.created_at ? new Date(msg.created_at).toISOString() : new Date().toISOString());

      return {
        id: (msg.id || msg.mid || msg.idstr || Math.random().toString(36).substr(2, 9)).toString(),
        senderName: user.screen_name || '未知用户',
        senderId: (user.id || msg.from_uid || 'unknown').toString(),
        content: msg.content || msg.text || '',
        timestamp: timestamp,
        avatar: user.profile_image_url || user.avatar_large || ''
      };
    });

    return { messages: parsedMessages };
  } catch (e) {
    console.error("本地解析出错:", e);
    return { messages: [] };
  }
};

